                        {
                            Session["Deal_area_new"] = Session["Deal_area_new"].ToString() + "एन. ए .आकारणी : " + txtNewArea12.Text + "\n ";
                        }

                        if (txtoldArea13.Text.ToString() != txtNewArea13.Text.ToString())
                        {
                            Session["Deal_area_new"] = Session["Deal_area_new"].ToString() + "फेरफार क्र " + txtNewArea13.Text + "\n";
                            change = "YES";
                        }

                        if (change == "YES")
                        {
                            Session["Deal_area_new"] = Session["Deal_area_new"].ToString() + "एकुण लागवड योग्य  : " + txtNewArea6.Text + "\n";
                        }
                        else
                        {
                            Session["Deal_area_new"] = "";
                        }
                        string _connectionString = (string)System.Configuration.ConfigurationManager.ConnectionStrings["District" + Convert.ToString(Session["DataBaseName"])].ConnectionString.ToString();
                        // string _connectionString = ((string)Session["DataBaseName"]).Split('#')[0] + "database = " + ((string)Session["DataBaseName"]).Split('#')[1] + ";" + (string)System.Configuration.ConfigurationManager.ConnectionStrings["LRSRO Connection StringMutation"].ConnectionString.ToString();
                        using (DbConnection connection = new NpgsqlConnection(_connectionString))
                        {
                            connection.Open();
                            DbTransaction dbTransaction;
                            using (dbTransaction = connection.BeginTransaction())
                            {
                                DbCommand dbCommand;
                                using (dbCommand = connection.CreateCommand())
                                {
                                    dbCommand.Transaction = dbTransaction;
                                    dbCommand.CommandType = CommandType.Text;
                                    try
                                    {

                                        //string deal_code_area = "51";
                                        string deal_text_area_old = Session["Deal_area_old"].ToString();
                                        string deal_text_area_new = Session["Deal_area_new"].ToString();
                                        if (Convert.ToString(deal_text_area_old) != "" && Convert.ToString(deal_text_area_new) != "")
                                        {
                                            int cnt_edit_deal = con.funReturnSingleValueInt(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_mut_deal_new", "count(*)", "ccode='" + Convert.ToString(Session["ccode"]) + "' and pin='" + Convert.ToString(Session["pin"]) + "' and pin1='" + Convert.ToString(Session["pin1"]) + "' and pin2='" + Convert.ToString(Session["pin2"]) + "' and pin3='" + Convert.ToString(Session["pin3"]) + "'and pin4='" + Convert.ToString(Session["pin4"]) + "' and pin5='" + Convert.ToString(Session["pin5"]) + "' and pin6='" + Convert.ToString(Session["pin6"]) + "' and pin7='" + Convert.ToString(Session["pin7"]) + "' and  pin8='" + Convert.ToString(Session["pin8"]) + "'", "");
                                            if (cnt_edit_deal == 0)
                                            {
                                                con.funInserSingleValueSevarthID(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_mut_deal_new", "ccode, pin, pin1, pin2, pin3, pin4, pin5, pin6,pin7, pin8, deal_code_area,deal_text_area_old, deal_text_area_new,edit_trans_no", "'" + Convert.ToString(Session["ccode"]) + "','" + Convert.ToString(Session["pin"]) + "','" + Convert.ToString(Session["pin1"]) + "','" + Convert.ToString(Session["pin2"]) + "','" + Convert.ToString(Session["pin3"]) + "','" + Convert.ToString(Session["pin4"]) + "','" + Convert.ToString(Session["pin5"]) + "','" + Convert.ToString(Session["pin6"]) + "','" + Convert.ToString(Session["pin7"]) + "','" + Convert.ToString(Session["pin8"]) + "','51' ,'" + deal_text_area_old + "','" + deal_text_area_new + "','" + Convert.ToString(Session["village_trans_cnt"]) + "'", Convert.ToString(Session["UserName"]), ref dbCommand);
                                            }
                                            else
                                            {
                                                con.funUpdatesEditTables(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_mut_deal_new", "deal_code_area='51',deal_text_area_old='" + Session["Deal_area_old"].ToString() + "',deal_text_area_new='" + Session["Deal_area_new"].ToString() + "', edit_trans_no= '" + Convert.ToString(Session["village_trans_cnt"]) + "'", "ccode = '" + (string)Session["ccode"] + "' and  pin='" + Convert.ToString(Session["pin"]) + "' and pin1='" + Convert.ToString(Session["pin1"]) + "'  and pin2='" + Convert.ToString(Session["pin2"]) + "'  and pin3='" + Convert.ToString(Session["pin3"]) + "'  and pin4='" + Convert.ToString(Session["pin4"]) + "'  and pin5='" + Convert.ToString(Session["pin5"]) + "'  and pin6='" + Convert.ToString(Session["pin6"]) + "'  and pin7='" + Convert.ToString(Session["pin7"]) + "'  and pin8='" + Convert.ToString(Session["pin8"]) + "'", "ccode = '" + (string)Session["ccode"] + "' and pin='" + Convert.ToString(Session["pin"]) + "' and pin1='" + Convert.ToString(Session["pin1"]) + "'  and pin2='" + Convert.ToString(Session["pin2"]) + "'  and pin3='" + Convert.ToString(Session["pin3"]) + "'  and pin4='" + Convert.ToString(Session["pin4"]) + "'  and pin5='" + Convert.ToString(Session["pin5"]) + "'  and pin6='" + Convert.ToString(Session["pin6"]) + "'  and pin7='" + Convert.ToString(Session["pin7"]) + "'  and pin8='" + Convert.ToString(Session["pin8"]) + "'", ref dbCommand, Convert.ToString(Session["UserName"]));
                                            }
                                        }
                                        dbTransaction.Commit();
                                        btnKshetraExit.Enabled = false;
                                    }
                                    catch (Exception ex)
                                    {
                                        dbTransaction.Rollback();
                                        ExceptionHandling excpt = new ExceptionHandling();
                                        if (Session["UserName"] != null)
                                            Session["Error"] = Session["Error"] = excpt.Getex(ex, page_name, Convert.ToString(Session["UserName"]), Convert.ToString(Session["DataBaseName"]));
                                        else
                                            Session["Error"] = excpt.Getex(ex, page_name, "UNKNOWN", Convert.ToString(Session["DataBaseName"]));
                                        string popupScript1 = "<script language='javascript'>alert('" + Convert.ToString(Session["Error"]) + "');</script>";
                                        ClientScript.RegisterStartupScript(GetType(), "PopupScript", popupScript1);
                                    }
                                }
                            }
                            connection.Close();
                        }

                        ScriptManager.RegisterStartupScript(Page, GetType(), @"poppup", @"document.getElementById('divpopup_area').style.display = 'block';", true);
                        string popupScript = "<script language='javascript'>alert('क्षेत्रातील माहिती साठवली.');</script>";
                        ClientScript.RegisterStartupScript(GetType(), "PopupScript", popupScript);

                        Panel41.Visible = true;
                        btnKshetraExit.Enabled = true;
                        btn_show.Enabled = true;
                    }

                }
                else
                {
                    string popupScript = "<script language='javascript'>alert('क्षेत्र संबंधी माहिती नसल्यास 0 भरा.');</script>";
                    ClientScript.RegisterStartupScript(GetType(), "PopupScript", popupScript);
                    return;
                }
                RadioButtonList1.Enabled = false;
            }



            catch (Exception ex)
            {
                ExceptionHandling excpt = new ExceptionHandling();
                if (Session["LoginID"] != null)
                    Session["Error"] = excpt.Getex(ex, page_name, Convert.ToString(Session["LoginID"]), Convert.ToString(Session["DataBaseName"]));
                else
                    Session["Error"] = excpt.Getex(ex, page_name, "UNKNOWN", Convert.ToString(Session["DataBaseName"]));
                string popupScript = "<script language='javascript'>alert('" + Convert.ToString(Session["Error"]) + "');</script>";


                ClientScript.RegisterStartupScript(GetType(), "PopupScript", popupScript);
            }
        }
    }

