    protected void btnEtarFerfarAdd_Click(object sender, EventArgs e)
    {
        ScriptManager.RegisterStartupScript(Page, GetType(), @"poppup", @"document.getElementById('div_iterfer').style.display = 'block';", true);
        Panel5.Visible = true;
        try
        {
            Session["found"] = 0;
            ViewState["found"] = 0;
            if (TextBox5.Text.Trim() == "")
                return;
            btnEtarFerfarNoExit.Enabled = true;
            for (int i = 0; i < lstNewFerfarNo.Items.Count; i++)
            {
                if (lstNewFerfarNo.Items[i].Text.Equals(TextBox5.Text))
                    ViewState["found"] = "1";
            }
            if (ViewState["found"] != null && !ViewState["found"].Equals("1"))
            {
                lstNewFerfarNo.Items.Add(TextBox5.Text.Trim());
                TextBox5.Text = "";
            }
        }
        catch (Exception ex)
        {
            ExceptionHandling excpt = new ExceptionHandling();
            if (Session["LoginID"] != null)
                Session["Error"] = excpt.Getex(ex, page_name, Convert.ToString(Session["LoginID"]), Convert.ToString(Session["DataBaseName"]));
            else
                Session["Error"] = excpt.Getex(ex, page_name, "UNKNOWN", Convert.ToString(Session["DataBaseName"]));
            string popupScript = "<script language='javascript'>alert('" + Convert.ToString(Session["Error"]) + "');</script>";


            ClientScript.RegisterStartupScript(GetType(), "PopupScript", popupScript);
        }
    }
