    protected void btnAddNameSave_Click(object sender, EventArgs e)
    {
        btnbackbgvt.Enabled = false;
        try
        {
            //[-- this button is to save the boja form dtls --]
            //[-- function of clsCommonFunction class is used to insert the boja form dtls when Operation is "NEW" or "UPDATE" --]

            if (ddlkhatatype.Text == "--निवडा--")
            {
                lblMessage.Visible = true;
                lblMessage.Text = "खाता प्रकार निवडा ";
                return;
            }
            //string _connectionString = Convert.ToString(Session["DataBaseName"]).Split('#')[0] + "database = " + Convert.ToString(Session["DataBaseName"]).Split('#')[1] + ";" + (string)System.Configuration.ConfigurationManager.ConnectionStrings["Database Connection String"].ConnectionString.ToString();
            string _connectionString = (string)System.Configuration.ConfigurationManager.ConnectionStrings["District" + Convert.ToString(Session["DataBaseName"])].ConnectionString.ToString();
            using (DbConnection connection = new NpgsqlConnection(_connectionString))
            {
                connection.Open();
                DbTransaction dbTransaction;
                using (dbTransaction = connection.BeginTransaction())
                {
                    DbCommand dbCommand;
                    using (dbCommand = connection.CreateCommand())
                    {
                        dbCommand.Transaction = dbTransaction;
                        dbCommand.CommandType = CommandType.StoredProcedure;
                        //-----
                        try
                        {
                            #region[--validations of khata type --]
                            int cnt_owners = gvKhataOwners.Rows.Count + grvVars.Rows.Count;
                            string status = "";
                            if (Convert.ToInt32(Session["khata_type"]) == 1)
                            {
                                if (cnt_owners == 1)
                                {
                                    status = "OK";
                                }
                                else
                                {
                                    status = "NOT OK";
                                }

                            }
                            else if (Convert.ToInt32(Session["khata_type"]) == 2 || Convert.ToInt32(Session["khata_type"]) == 3)
                            {
                                if (cnt_owners == 1)
                                {
                                    status = "NOT OK";
                                }
                                else
                                {
                                    status = "OK";
                                }
                            }
                            else
                            {
                                status = "OK";
                            }

                            #endregion[--validations of khata type --]

                            if (status == "OK")
                            {
                                lblMessage.Visible = false;
                                lblMessage.Text = " ";
                                DataTable dtboja = new DataTable();
                                Boja_table(ref dtboja);

                                DataTable dtpins = (DataTable)Session["tblSurveypin1"];
                                DataTable dtnewname = (DataTable)Session["tblVars"];
                                if (Convert.ToString(Session["editf7k_add"]) != "YES")
                                {
                                    int cnt_editf7k_Add = con.funReturnSingleValueInt(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_form7_khata", "count(*)", "ccode = '" + (string)Session["ccode"] + "' and pin='" + Convert.ToString(Session["pin"]) + "' and pin1='" + Convert.ToString(Session["pin1"]) + "' and  pin2='" + Convert.ToString(Session["pin2"]) + "' and pin3='" + Convert.ToString(Session["pin3"]) + "' and pin4='" + Convert.ToString(Session["pin4"]) + "' and pin5='" + Convert.ToString(Session["pin5"]) + "' and pin6='" + Convert.ToString(Session["pin6"]) + "'  and pin7='" + Convert.ToString(Session["pin7"]) + "' and pin8 ='" + Convert.ToString(Session["pin8"]) + "' ", "");
                                    if (cnt_editf7k_Add == 0)
                                    {
                                        foreach (DataRow drpins in dtpins.Rows)
                                        {
                                            cnt_editf7k_Add = con.funReturnSingleValueInt(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_form7_khata", "count(*)", "ccode = '" + (string)Session["ccode"] + "' and  pin='" + Convert.ToString(drpins["pin"]) + "' and pin1='" + Convert.ToString(drpins["pin1"]) + "' and  pin2='" + Convert.ToString(drpins["pin2"]) + "' and pin3='" + Convert.ToString(drpins["pin3"]) + "' and pin4='" + Convert.ToString(drpins["pin4"]) + "' and pin5='" + Convert.ToString(drpins["pin5"]) + "' and pin6='" + Convert.ToString(drpins["pin6"]) + "'  and pin7='" + Convert.ToString(drpins["pin7"]) + "' and pin8 ='" + Convert.ToString(drpins["pin8"]) + "' ", "");
                                            if (cnt_editf7k_Add == 0)
                                            {
                                                con.funPopulateValueSevarth((string)Session["SchemaName"], (string)Session["SchemaName"] + ".edit_form7_khata", " ccode,pin, pin1, pin2, pin3, pin4, pin5, pin6,pin7, pin8, khata_no,fname, mname, lname,topan_name,usrno,mut_no,marked,khata_type,total_area_h,assessment, anne,pai,potkharaba,edit_trans_no,edit_appname,edit_flag", " ccode,pin, pin1, pin2, pin3, pin4, pin5, pin6,pin7, pin8, khata_no,fname, mname, lname,topan_name,usrno,mut_no,marked,khata_type,total_area_h,assessment, anne,pai,potkharaba,'" + Convert.ToString(Session["village_trans_cnt"]) + "','reEdit','31'", " ccode = '" + (string)Session["ccode"] + "' and pin='" + Convert.ToString(drpins["pin"]) + "' and pin1='" + Convert.ToString(drpins["pin1"]) + "' and  pin2='" + Convert.ToString(drpins["pin2"]) + "' and pin3='" + Convert.ToString(drpins["pin3"]) + "' and pin4='" + Convert.ToString(drpins["pin4"]) + "' and pin5='" + Convert.ToString(drpins["pin5"]) + "' and pin6='" + Convert.ToString(drpins["pin6"]) + "'  and pin7='" + Convert.ToString(drpins["pin7"]) + "' and pin8 ='" + Convert.ToString(drpins["pin8"]) + "' ", (string)Session["SchemaName"] + ".form7_khata", Convert.ToString(Session["UserName"]), ref dbCommand);
                                            }
                                        }
                                    }

                                    DataTable dt_khata = (DataTable)Session["Khata_no_on_survey"];
                                    for (int j = 0; j < dt_khata.Rows.Count; j++)
                                    {

                                        int chk_edit_hd_khata = con.funReturnSingleValueInt(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_holder_detail", "count(*) ", "ccode = '" + (string)Session["ccode"] + "' and  khata_no='" + Convert.ToString(Convert.ToString(dt_khata.Rows[j][0])) + "'", "");
                                        if (chk_edit_hd_khata == 0)
                                        {
                                            con.funPopulateValueSevarth((string)Session["SchemaName"], (string)Session["SchemaName"] + ".edit_holder_detail", " ccode,fname, mname, lname, topan_name,khata_no, khata_type,edit_trans_no,edit_appname,edit_flag", " ccode, fname, mname, lname, topan_name,khata_no,khata_type,'" + Convert.ToString(Session["village_trans_cnt"]) + "','reEdit','31'", " ccode = '" + (string)Session["ccode"] + "'   and khata_no='" + Convert.ToString(dt_khata.Rows[j][0]) + "'", (string)Session["SchemaName"] + ".holder_detail", Convert.ToString(Session["UserName"]), ref dbCommand);
                                        }
                                    }
                                }
                                // asuming on all khata have same count 
                                decimal max_usrno_khata = Convert.ToDecimal(Session["max_usrno_khata"]) + 1;

                                for (int j = 0; j < dtpins.Rows.Count; j++)
                                {
                                    decimal usrno = max_usrno_khata;
                                    for (int i = 0; i < dtnewname.Rows.Count; i++)
                                    {
                                        int cnt_editf7k_Add = con.funReturnSingleValueInt(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_form7_khata", "count(*)", "ccode = '" + (string)Session["ccode"] + "' and pin='" + Convert.ToString(dtpins.Rows[j]["pin"]) + "' and pin1='" + Convert.ToString(dtpins.Rows[j]["pin1"]) + "' and  pin2='" + Convert.ToString(dtpins.Rows[j]["pin2"]) + "' and pin3='" + Convert.ToString(dtpins.Rows[j]["pin3"]) + "' and pin4='" + Convert.ToString(dtpins.Rows[j]["pin4"]) + "' and pin5='" + Convert.ToString(dtpins.Rows[j]["pin5"]) + "' and pin6='" + Convert.ToString(dtpins.Rows[j]["pin6"]) + "'  and pin7='" + Convert.ToString(dtpins.Rows[j]["pin7"]) + "' and pin8 ='" + Convert.ToString(dtpins.Rows[j]["pin8"]) + "' and fname='" + Convert.ToString(dtnewname.Rows[i]["fname"]).Trim() + "'  and mname='" + Convert.ToString(dtnewname.Rows[i]["mname"]).Trim() + "' and lname='" + Convert.ToString(dtnewname.Rows[i]["lname"]).Trim() + "' and topan_name='" + Convert.ToString(dtnewname.Rows[i]["topan_name"]).Trim() + "' and khata_no='" + Convert.ToString(Session["khata_no"]).Trim() + "' and edit_flag<>'34' ", "");
