        CheckBox ckhbracket = (CheckBox)sender;
        CheckBox chkkansrem = (CheckBox)gdvEtarHakka.HeaderRow.FindControl("chkkansrem");

        if (ckhbracket.Checked == true)
        {
            for (int i = 0; i < gdvEtarHakka.Rows.Count; i++)
            {
                ((CheckBox)gdvEtarHakka.Rows[i].FindControl("chkbrk")).Checked = true;
                ((CheckBox)gdvEtarHakka.Rows[i].FindControl("chkbrkrem")).Enabled = false;
            }
            chkkansrem.Enabled = false;
        }
        else
        {
            for (int i = 0; i < gdvEtarHakka.Rows.Count; i++)
            {
                ((CheckBox)gdvEtarHakka.Rows[i].FindControl("chkbrk")).Checked = false;
                ((CheckBox)gdvEtarHakka.Rows[i].FindControl("chkbrkrem")).Enabled = true;
            }
            chkkansrem.Enabled = true;
        }




    }

