    protected void chkbrkrem_CheckedChanged1(object sender, EventArgs e)
    {
        CheckBox chkbrkrem = (CheckBox)sender;
        GridViewRow gvr = ((GridViewRow)((Control)sender).Parent.Parent);
        CheckBox chk = (CheckBox)gvr.FindControl("chkbrk");

        if (chkbrkrem.Checked == true)
        {
            chk.Enabled = false;
            chkbrkrem.Enabled = true;
            chk.Checked = false;
        }
        else
        {
            chk.Checked = true;
            // chk.Enabled = true;
            // chkbrkrem.Enabled = false;
        }

        DataTable dtnew = (DataTable)Session["gridetarnew"];
        DataRow dr = dtnew.Rows[gvr.RowIndex];
        if (Convert.ToString(Session["upadte"]) != "true")
        {
            dtnew.Columns.Add("old_tenant_name");
            dtnew.Columns.Add("old_mut_no");
            Session["upadte"] = "true";
        }
        dr["old_tenant_name"] = dr["tenant_name"];
        dr["old_mut_no"] = dr["mut_no"];
        dtnew.AcceptChanges();


        // DataTable dtnew = (DataTable)Session["gridetarnew"];
        for (int s = 0; s < gdvEtarHakka.Rows.Count; s++)
        {
            CheckBox chk1 = (CheckBox)gdvEtarHakka.Rows[s].FindControl("chkbrk");
            CheckBox chkrem = (CheckBox)gdvEtarHakka.Rows[s].FindControl("chkbrkrem");
            if (chk1.Checked == true)
            {
                dtnew.Rows[s]["checked"] = "1";
                dtnew.Rows[s]["checkedrem"] = "0";
            }
            else
            {
                dtnew.Rows[s]["checked"] = "0";
                // dtnew.Rows[s]["checkedrem"] = "1";
            }
            if (chkrem.Checked == true)
            {
                dtnew.Rows[s]["checkedrem"] = "1";
                dtnew.Rows[s]["checked"] = "0";
            }
            else
            {
                dtnew.Rows[s]["checkedrem"] = "0";
                // dtnew.Rows[s]["checked"] = "1";
            }

        }
        Session["gridetarnewbrkrem"] = dtnew;
        Session["gridetarnew"] = dtnew;

        DataTable dtw = new DataTable();
        dtw = dtnew.Clone();
        DataRow drUnBracket = dtnew.Rows[gvr.RowIndex];

        if (ViewState["gridUnBracket"] == null)
        {
            dtw.ImportRow(drUnBracket);
            //deleted rows audit
            ViewState["gridUnBracket"] = dtw;
        }
        else
        {
            dtw = (DataTable)ViewState["gridUnBracket"];
            dtw.ImportRow(drUnBracket);
            //deleted rows audit
            ViewState["gridUnBracket"] = dtw;
        }
    }

