    protected void gdvEtarHakka_RowDeleting(object sender, GridViewDeleteEventArgs e)
    {

        if (ViewState["gridetar"] != null)//Check if the session value is not null
        {
            DataTable dt_seller_grid = (DataTable)Session["gridetarnew"];//Copy the Session data into a temporary datatable
            int i = e.RowIndex;//Current row index

            Label lblColumn1 = (Label)gdvEtarHakka.Rows[e.RowIndex].FindControl("lblColumn1");
            Label lblColumn2 = (Label)gdvEtarHakka.Rows[e.RowIndex].FindControl("lblColumn2");
            Label lblpins = (Label)gdvEtarHakka.Rows[e.RowIndex].FindControl("lblpins");
            DataTable dtw = new DataTable();
            dtw = dt_seller_grid.Clone();
            DataRow drdelete = dt_seller_grid.Rows[i];

            if (ViewState["gridDelete"] == null)
            {
                dtw.ImportRow(drdelete);
                //deleted rows audit
                ViewState["gridDelete"] = dtw;
            }
            else
            {
                dtw = (DataTable)ViewState["gridDelete"];
                dtw.ImportRow(drdelete);
                //deleted rows audit
                ViewState["gridDelete"] = dtw;
            }

            dt_seller_grid.Rows.RemoveAt(i);//Remove the row from the datatable
            dt_seller_grid.AcceptChanges();
            ViewState["gridetarhakka"] = dt_seller_grid;//Keep the datatable in Session

            gdvEtarHakka.DataSource = dt_seller_grid;
            gdvEtarHakka.DataBind();
            ChkboxChanges();
        }
    }
    protected void gdvEtarHakka_RowEditing(object sender, GridViewEditEventArgs e)
    {


        DataTable dt = (DataTable)Session["gridetarnew"];

        //Copy the Session data of new buyers into a tamp datatable
        gdvEtarHakka.EditIndex = e.NewEditIndex;//Set the edit index of the gridview
        gdvEtarHakka.DataSource = dt;
        gdvEtarHakka.DataBind();

