    protected void gdvEtarHakka_RowUpdating(object sender, GridViewUpdateEventArgs e)
    {
        DataTable dt = (DataTable)Session["gridetarnew"];

        if (Convert.ToString(Session["upadte"]) != "true")
        {
            dt.Columns.Add("old_tenant_name");
            dt.Columns.Add("old_mut_no");
            Session["upadte"] = "true";
        }
        TextBox grdtxtdetails = (TextBox)gdvEtarHakka.Rows[e.RowIndex].FindControl("grdtxtdetails");
        TextBox grdtxtmutno = (TextBox)gdvEtarHakka.Rows[e.RowIndex].FindControl("grdtxtmutno");




        int i = Convert.ToInt32(e.RowIndex);//Current row index
        DataRow dr = dt.Rows[i];

        dr["old_tenant_name"] = dr["tenant_name"];
        dr["old_mut_no"] = dr["mut_no"];//Copy the textbox data into the current datarow's other_rights column

        dr["tenant_name"] = grdtxtdetails.Text;
        dr["mut_no"] = grdtxtmutno.Text;
        dt.AcceptChanges();

        // int j = Convert.ToInt32(e.RowIndex);
        DataTable dtw = new DataTable();
        dtw = dt.Clone();
        DataRow drupdate = dt.Rows[i];

        if (ViewState["gridUpdate"] == null)
        {
            dtw.ImportRow(drupdate);
            //deleted rows audit
            ViewState["gridUpdate"] = dtw;
        }
        else
        {
            dtw = (DataTable)ViewState["gridUpdate"];
            dtw.ImportRow(drupdate);
            //deleted rows audit
            ViewState["gridUpdate"] = dtw;
        }

        //DataSet after changes/Durusti
        ViewState["gridetarhakka"] = dt;//Keep the datatable in Session
        gdvEtarHakka.EditIndex = -1;
        gdvEtarHakka.DataSource = dt;
        gdvEtarHakka.DataBind();
        ChkboxChanges();

    }
    protected void gdvEtarHakka_RowCancelingEdit(object sender, GridViewCancelEditEventArgs e)
    {
        gdvEtarHakka.EditIndex = -1;
        DataTable dt = (DataTable)Session["gridetarnew"];
        gdvEtarHakka.DataSource = dt;
        gdvEtarHakka.DataBind();
        ChkboxChanges();
    }

    public void ChkboxChanges()
    {
        int count = 0, count1 = 0;
        DataTable dt = (DataTable)Session["gridetarnew"];
        for (int s = 0; s < gdvEtarHakka.Rows.Count; s++)
        {
            CheckBox chk = (CheckBox)gdvEtarHakka.Rows[s].FindControl("chkbrk");
            CheckBox chkrem = (CheckBox)gdvEtarHakka.Rows[s].FindControl("chkbrkrem");

            if (dt.Rows[s]["checked"].ToString() == "1")
            {
                chk.Checked = true;
            }
            else
            {
                chk.Checked = false;
            }

            if (dt.Rows[s]["checkedrem"].ToString() == "1")
            {
                chkrem.Checked = true;
            }
            else
            {
                chkrem.Checked = false;
            }

            if (dt.Rows[s]["marked"].ToString() == "Y")
            {
                chk.Enabled = false;
                chkrem.Enabled = true;
                count++;
            }
            else
            {
                chk.Enabled = true;
                chkrem.Enabled = false;
                count1++;
            }
        }
        if (count == gdvEtarHakka.Rows.Count)
        {
            if (count > 0)
            {
                CheckBox chkkans = (CheckBox)gdvEtarHakka.HeaderRow.FindControl("chkkans");
                chkkans.Enabled = false;
            }
        }
        if (count1 == gdvEtarHakka.Rows.Count)
        {
            if (count1 > 0)
            {
                CheckBox chkkansrem = (CheckBox)gdvEtarHakka.HeaderRow.FindControl("chkkansrem");
                chkkansrem.Enabled = false;
            }
        }

    }

