    public void ChkboxChangeskul()
    {
        int count = 0, count1 = 0;
        DataTable dt = (DataTable)Session["gridetarnewkul"];
        for (int s = 0; s < gdvKul.Rows.Count; s++)
        {
            CheckBox chk = (CheckBox)gdvKul.Rows[s].FindControl("chkbrkkul");
            CheckBox chkrem = (CheckBox)gdvKul.Rows[s].FindControl("chkbrkremkul");

            if (dt.Rows[s]["checked"].ToString() == "1")
            {
                chk.Checked = true;
            }
            else
            {
                chk.Checked = false;
            }

            if (dt.Rows[s]["checkedrem"].ToString() == "1")
            {
                chkrem.Checked = true;
            }
            else
            {
                chkrem.Checked = false;
            }

            if (dt.Rows[s]["marked"].ToString() == "Y")
            {
                chk.Enabled = false;
                chkrem.Enabled = true;
                count++;
            }
            else
            {
                chk.Enabled = true;
                chkrem.Enabled = false;
                count1++;
            }
        }
        if (count == gdvKul.Rows.Count)
        {
            CheckBox chkkans = (CheckBox)gdvKul.HeaderRow.FindControl("chkkanskul");
            chkkans.Enabled = false;
        }
        if (count1 == gdvKul.Rows.Count)
        {
            CheckBox chkkansrem = (CheckBox)gdvKul.HeaderRow.FindControl("chkkansremkul");
            chkkansrem.Enabled = false;
        }

    }

