    protected void gdvKul_RowUpdating(object sender, GridViewUpdateEventArgs e)
    {
        DataTable dt = (DataTable)Session["gridetarnewkul"];
        if (Convert.ToString(Session["upadte"]) != "truekul")
        {
            dt.Columns.Add("old_tenant_name");
            dt.Columns.Add("old_mut_no");
            Session["upadte"] = "truekul";
        }


        TextBox grdtxtdetailskul = (TextBox)gdvKul.Rows[e.RowIndex].FindControl("grdtxtdetailskul");
        TextBox grdtxtmutnokul = (TextBox)gdvKul.Rows[e.RowIndex].FindControl("grdtxtmutnokul");
        int i = Convert.ToInt32(e.RowIndex);//Current row index
        DataRow dr = dt.Rows[i];

        dr["old_tenant_name"] = dr["tenant_name"];
        dr["old_mut_no"] = dr["mut_no"];//Copy the textbox data into the current datarow's other_rights column
        dr["tenant_name"] = grdtxtdetailskul.Text;
        dr["mut_no"] = grdtxtmutnokul.Text;//Copy the textbox data into the current datarow's other_rights column
        dt.AcceptChanges();

        DataTable dtw = new DataTable();
        // dskulexist.Tables.Add(dtw);
        dtw = dt.Clone();
        DataRow drUpdatekul = dt.Rows[i];

        if (ViewState["gridUpdatekul"] == null)
        {
            dtw.ImportRow(drUpdatekul);
            ViewState["gridUpdatekul"] = dtw;
        }
        else
        {
            dtw = (DataTable)ViewState["gridUpdatekul"];
            dtw.ImportRow(drUpdatekul);
            ViewState["gridUpdatekul"] = dtw;
        }

        //DataSet after changes/Durusti
        ViewState["gridetarhakkakul"] = dt;//Keep the datatable in Session
        Session["gridetarnewkul"] = ViewState["gridetarhakkakul"];
        gdvKul.EditIndex = -1;
        gdvKul.DataSource = dt;
        gdvKul.DataBind();
        ChkboxChangeskul();

    }
    protected void gdvKul_RowDeleting(object sender, GridViewDeleteEventArgs e)
    {
        if (ViewState["dskul"] != null)//Check if the session value is not null
        {
            DataTable dskulexist = (DataTable)Session["gridetarnewkul"];//
            // DataTable dt_seller_grid = (DataTable)Session["gridetarnew"];//Copy the Session data into a temporary datatable
            int i = e.RowIndex;//Current row index

            Label lblColumn1 = (Label)gdvKul.Rows[e.RowIndex].FindControl("lblColumn1kul");
            Label lblColumn2 = (Label)gdvKul.Rows[e.RowIndex].FindControl("lblColumn2kul");
            //  Label lblpins = (Label)gdvKul.Rows[e.RowIndex].FindControl("lblpins");

            DataTable dtw = new DataTable();
            // dskulexist.Tables.Add(dtw);
            dtw = dskulexist.Clone();
            DataRow drdelete = dskulexist.Rows[i];

            if (ViewState["gridDeletekul"] == null)
            {
                dtw.ImportRow(drdelete);
                //deleted rows audit
                ViewState["gridDeletekul"] = dtw;
            }
            else
            {
                dtw = (DataTable)ViewState["gridDeletekul"];
                dtw.ImportRow(drdelete);
                //deleted rows audit
                ViewState["gridDeletekul"] = dtw;
            }

            dskulexist.Rows.RemoveAt(i);//Remove the row from the datatable
            dskulexist.AcceptChanges();
            ViewState["gridetarhakkakul"] = dskulexist;//Keep the datatable in Session
            Session["gridetarnewkul"] = ViewState["gridetarhakkakul"];
            gdvKul.DataSource = dskulexist;
            gdvKul.DataBind();
            ChkboxChangeskul();
        }
    }
