    protected void btnNewKulAdd_Click(object sender, EventArgs e)
    {
        try
        {
            btnNewKulExit.Enabled = true;
            ScriptManager.RegisterStartupScript(Page, GetType(), @"poppup", @"document.getElementById('div_kul2').style.display = 'block';", true);
            Panelkul.Visible = true;
            if (ddlNewKulType.Enabled.Equals(false))
            {
                string popupScript = "<script language='javascript'>alert(' please click add  !  ');</script>";
                ClientScript.RegisterStartupScript(GetType(), "PopupScript", popupScript);
