                    drq[5] = ((TextBox)gdvNewKul.Rows[index].FindControl("grd2text6")).Text;
                    dsgrd.Tables[0].Rows.Add(drq);
                }
            }
            ViewState["grdkulnew"] = dsgrd;

            DataSet ds1 = (DataSet)ViewState["grdkulnew"];
            if (ds1 == null)
            {
                DataSet dsk = new newkul();
