                ViewState["grdkulnew"] = ds1;
            }
            else
            {
                DataRow dr = ds1.Tables[0].NewRow();
                //dr[0] = Session["mut_no"];
                dr[0] = "";
                dr[1] = "";
                dr[2] = "";
                dr[3] = "";
                dr[4] = "";
                dr[5] = ddlNewKulType.SelectedItem.Value;
                ds1.Tables[0].Rows.Add(dr);
                gdvNewKul.DataSource = ds1;
                gdvNewKul.DataBind();
                ViewState["grdkulnew"] = ds1;
            }

            if (gdvNewKul.Rows.Count > 0)
            {
                for (int index = 0; index < gdvNewKul.Rows.Count; index++)
                {
                    TextBox t2 = (TextBox)gdvNewKul.Rows[index].FindControl("grd2text2");
                    TextBox t3 = (TextBox)gdvNewKul.Rows[index].FindControl("grd2text3");
                    TextBox t4 = (TextBox)gdvNewKul.Rows[index].FindControl("grd2text4");
                    TextBox t5 = (TextBox)gdvNewKul.Rows[index].FindControl("grd2text5");
                    t2.Attributes.Add("onkeypress", "IsAlphabet(this,event)");
                    t3.Attributes.Add("onkeypress", "IsDigitAndDecimal(this,event)");
                    t4.Attributes.Add("onkeypress", "IsDigitAndDecimal(this,event)");
                    t5.Attributes.Add("onkeypress", "IsDigitAndDecimal(this,event)");
                }
