    public DataTable createTable(DataTable TableName, string colName)
    {
        string[] strSplitArr = colName.Split(',');
        int count = strSplitArr.Length;
        TableName.Columns.Clear();
        for (int i = 0; i <= count - 1; i++)
        {
            TableName.Columns.Add(strSplitArr[i]);
        }
        TableName.AcceptChanges();
        return TableName;
    }

    protected void btnakarni_Click(object sender, EventArgs e)
    {
        try
        {
            //seema14
            // ScriptManager.RegisterStartupScript(Page, GetType(), @"poppup", @"document.getElementById('divpopup_bhogvatdar').style.display = 'block';", true);

            //  PanelGhenara.Visible = true;
            for (int p = 0; p < gdvOldBhogvatdar1.Rows.Count; p++)
            {
                TextBox txtarea = (TextBox)gdvOldBhogvatdar1.Rows[p].FindControl("grd2text6");
                TextBox txtakarni = (TextBox)gdvOldBhogvatdar1.Rows[p].FindControl("grd2text7");
                string area_akarni = null;

                int f7a_edit_cnt = con.funReturnSingleValueInt((string)Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_form7_area", "Count(*)", "ccode = '" + Convert.ToString(Session["ccode"]) + "' and pin='" + Convert.ToString(Session["pin"]) + "' and pin1='" + Convert.ToString(Session["pin1"]) + "' and pin2='" + Convert.ToString(Session["pin2"]) + "' and pin3='" + Convert.ToString(Session["pin3"]) + "' and pin4='" + Convert.ToString(Session["pin4"]) + "' and pin5='" + Convert.ToString(Session["pin5"]) + "' and pin6='" + Convert.ToString(Session["pin6"]) + "'  and pin7='" + Convert.ToString(Session["pin7"]) + "' and pin8 ='" + Convert.ToString(Session["pin8"]) + "'", "");
                if (f7a_edit_cnt > 0)
                {
                    area_akarni = con.funReturnSingleValue(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_form7_area", "net_culti_area_h||'#'||assessment", "ccode = '" + Convert.ToString(Session["ccode"]) + "' and pin='" + Convert.ToString(Session["pin"]) + "' and pin1='" + Convert.ToString(Session["pin1"]) + "' and pin2='" + Convert.ToString(Session["pin2"]) + "' and pin3='" + Convert.ToString(Session["pin3"]) + "' and pin4='" + Convert.ToString(Session["pin4"]) + "' and pin5='" + Convert.ToString(Session["pin5"]) + "' and pin6='" + Convert.ToString(Session["pin6"]) + "'  and pin7='" + Convert.ToString(Session["pin7"]) + "' and pin8 ='" + Convert.ToString(Session["pin8"]) + "'", "");
                }
                else
                {
                    area_akarni = con.funReturnSingleValue(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".form7_area", "net_culti_area_h||'#'||assessment", "ccode = '" + Convert.ToString(Session["ccode"]) + "' and pin='" + Convert.ToString(Session["pin"]) + "' and pin1='" + Convert.ToString(Session["pin1"]) + "' and pin2='" + Convert.ToString(Session["pin2"]) + "' and pin3='" + Convert.ToString(Session["pin3"]) + "' and pin4='" + Convert.ToString(Session["pin4"]) + "' and pin5='" + Convert.ToString(Session["pin5"]) + "' and pin6='" + Convert.ToString(Session["pin6"]) + "'  and pin7='" + Convert.ToString(Session["pin7"]) + "' and pin8 ='" + Convert.ToString(Session["pin8"]) + "'", "");
                }


                if (area_akarni != "" && area_akarni != null && Convert.ToDecimal(area_akarni.Split('#')[1]) != 0 && Convert.ToDecimal(area_akarni.Split('#')[0]) != 0)
                    txtakarni.Text = Convert.ToString(Math.Round((Convert.ToDecimal(txtarea.Text) * (Convert.ToDecimal(area_akarni.Split('#')[1]) / Convert.ToDecimal(area_akarni.Split('#')[0]))), 2));
            }


        }
        catch (Exception ex)
        {
            ExceptionHandling excpt = new ExceptionHandling();
            if (Session["LoginID"] != null)
                Session["Error"] = excpt.Getex(ex, page_name, Convert.ToString(Session["LoginID"]), Convert.ToString(Session["DataBaseName"]));
            else
                Session["Error"] = excpt.Getex(ex, page_name, "UNKNOWN", Convert.ToString(Session["DataBaseName"]));
            string popupScript = "<script language='javascript'>alert('" + Convert.ToString(Session["Error"]) + "');</script>";
            ClientScript.RegisterStartupScript(GetType(), "PopupScript", popupScript);
        }
    }
