    protected void ddlname_SelectedIndexChanged(object sender, EventArgs e)
    {
        if (ddlname.SelectedIndex != -1 && ddlname.SelectedItem.Text != "")
            ViewState["mkhatano"] = ddlname.SelectedValue.Split('#')[0].ToString();


        DataSet ds = new DataSet();
        DataSet ds1 = new DataSet();
        ds1 = (DataSet)ViewState["grdNewkhata"];



        if (ds1 == null)
        {

            int eHD_chk = con.funReturnSingleValueInt(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_holder_detail", "count(*)", "ccode = '" + Convert.ToString(Session["ccode"]) + "'  and khata_no = '" + (string)ViewState["mkhatano"] + "'", "");

            if (eHD_chk == 0)
            {
                ds = con.funReturnDataSet(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".holder_detail AS a left OUTER JOIN " + Session["SchemaName"].ToString() + ".m_khata_type AS p ON a.khata_type = p.khata_type", "fname,mname,lname,topan_name , khata_description,khata_no ,usrno,caste_code as buyer_area_tot,caste_code as na_assessment,caste_code as buyer_anne,caste_code as buyer_pai, caste_code as buyer_pot", "ccode = '" + Convert.ToString(Session["ccode"]) + "'  and khata_no = '" + (string)ViewState["mkhatano"] + "' ", "usrno");
            }
            else
            {
                ds = con.funReturnDataSet(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_holder_detail AS a left OUTER JOIN " + Session["SchemaName"].ToString() + ".m_khata_type AS p ON a.khata_type = p.khata_type", "fname,mname,lname,topan_name , khata_description,khata_no ,usrno,caste_code as buyer_area_tot,caste_code as na_assessment,caste_code as buyer_anne,caste_code as buyer_pai, caste_code as buyer_pot", "ccode = '" + Convert.ToString(Session["ccode"]) + "'  and khata_no = '" + (string)ViewState["mkhatano"] + "' and edit_flag<>'34'", "usrno");
            }
            gdvNewBhogvatdar.DataSource = ds.Tables[0].DefaultView.ToTable(true, "fname", "mname", "lname", "topan_name", "khata_no", "usrno");
            gdvNewBhogvatdar.DataBind();

            txtKhataNoAdd.Text = "";
            //ViewState["grdNewkhata"] = ds.Tables[0].DefaultView.ToTable(true, "fname", "mname", "lname", "topan_name", "khata_no", "usrno");
            ViewState["grdNewkhata"] = ds;
            ViewState["mkhatano"] = "";
            btnNewKhataAddSave.Visible = true;
            btnNewKhataAddSave.Enabled = true;
        }
        else
        {

            int eHD_chk = con.funReturnSingleValueInt(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_holder_detail", "count(*)", "ccode = '" + Convert.ToString(Session["ccode"]) + "'  and khata_no = '" + (string)ViewState["mkhatano"] + "'", "");

            if (eHD_chk == 0)
            {
                ds = con.funReturnDataSet(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".holder_detail AS a left OUTER JOIN " + Session["SchemaName"].ToString() + ".m_khata_type AS p ON a.khata_type = p.khata_type", "fname,mname,lname,topan_name , khata_description,khata_no,usrno", "ccode = '" + Convert.ToString(Session["ccode"]) + "'  and khata_no = '" + (string)ViewState["mkhatano"] + "' ", "usrno");
            }
            else
            {
                ds = con.funReturnDataSet(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_holder_detail AS a left OUTER JOIN " + Session["SchemaName"].ToString() + ".m_khata_type AS p ON a.khata_type = p.khata_type", "fname,mname,lname,topan_name , khata_description,khata_no,usrno", "ccode = '" + Convert.ToString(Session["ccode"]) + "'  and khata_no = '" + (string)ViewState["mkhatano"] + "' and edit_flag<>'34'", "usrno");
            }
            for (int i = 0; i <= ds.Tables[0].Rows.Count - 1; i++)
            {
                DataRow dr = ds1.Tables[0].NewRow();
                dr["fname"] = ds.Tables[0].Rows[i][0].ToString();
                dr["mname"] = ds.Tables[0].Rows[i][1].ToString();
                dr["lname"] = ds.Tables[0].Rows[i][2].ToString();
                dr["topan_name"] = ds.Tables[0].Rows[i][3].ToString();
                dr["khata_no"] = ds.Tables[0].Rows[i][5].ToString();
                dr["usrno"] = ds.Tables[0].Rows[i]["usrno"].ToString();

                ds1.Tables[0].Rows.Add(dr);
            }
            if (ds1.Tables[0].Rows.Count > 0)
            {
                ViewState["found"] = 0;

                if (Convert.ToInt32(ViewState["found"]) == 0)
                {
                    gdvNewBhogvatdar.DataSource = ds1.Tables[0].DefaultView.ToTable(true, "fname", "mname", "lname", "topan_name", "khata_no", "usrno");
                    gdvNewBhogvatdar.DataBind();
                    // ViewState["grdNewkhata"] = ds1.Tables[0].DefaultView.ToTable(true, "fname", "mname", "lname", "topan_name", "khata_no", "usrno");
                    ViewState["grdNewkhata"] = ds1;
                    btnNewKhataAddSave.Visible = true;
                    btnNewKhataAddSave.Enabled = true;
                }
            }
            ViewState["mkhatano"] = "";
        }
    }
