    protected void gdvNewBhogvatdar_RowDeleting1(object sender, GridViewDeleteEventArgs e)
    {
        int index = e.RowIndex;
        DataTable dt_addkhata_delete = new DataTable();
        DataSet ds_addkhata_delete = (DataSet)ViewState["grdNewkhata"];
        dt_addkhata_delete = ds_addkhata_delete.Tables[0].Clone();
        DataRow dr_delete = dt_addkhata_delete.NewRow();

        dr_delete["khata_no"] = ((Label)gdvNewBhogvatdar.Rows[index].FindControl("lblColumn1")).Text;
        dt_addkhata_delete.Rows.Add(dr_delete);

        // string _connectionString = Convert.ToString(Session["DataBaseName"]).Split('#')[0] + "database = " + Convert.ToString(Session["DataBaseName"]).Split('#')[1] + ";" + (string)System.Configuration.ConfigurationManager.ConnectionStrings["Database Connection String"].ConnectionString.ToString();
        string _connectionString = (string)System.Configuration.ConfigurationManager.ConnectionStrings["District" + Convert.ToString(Session["DataBaseName"])].ConnectionString.ToString();
        using (DbConnection connection = new NpgsqlConnection(_connectionString))
        {
            connection.Open();
            DbTransaction dbTransaction;
            using (dbTransaction = connection.BeginTransaction())
            {
                DbCommand dbCommand;
                using (dbCommand = connection.CreateCommand())
                {
                    dbCommand.Transaction = dbTransaction;
                    dbCommand.CommandType = CommandType.StoredProcedure;
                    //-----
                    try
                    {
                        foreach (DataRow dr_ in ds_addkhata_delete.Tables[0].Select("khata_no='" + dr_delete["khata_no"] + "'"))
                        {
                            ds_addkhata_delete.Tables[0].Rows.Remove(dr_);
                            con.funDeleteRecord(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_form7_khata", "ccode = '" + (string)Session["ccode"] + "' and pin='" + Convert.ToString(Session["pin"]) + "' and pin1='" + Convert.ToString(Session["pin1"]) + "' and  pin2='" + Convert.ToString(Session["pin2"]) + "' and pin3='" + Convert.ToString(Session["pin3"]) + "' and pin4='" + Convert.ToString(Session["pin4"]) + "' and pin5='" + Convert.ToString(Session["pin5"]) + "' and pin6='" + Convert.ToString(Session["pin6"]) + "'  and pin7='" + Convert.ToString(Session["pin7"]) + "' and pin8 ='" + Convert.ToString(Session["pin8"]) + "' and khata_no='" + dr_delete["khata_no"] + "'", ref dbCommand);
                            // con.funDeleteRecord(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_form7_khata", "ccode = '" + (string)Session["ccode"] + "' and pin='" + Convert.ToString(Session["pin"]) + "' and pin1='" + Convert.ToString(Session["pin1"]) + "' and  pin2='" + Convert.ToString(Session["pin2"]) + "' and pin3='" + Convert.ToString(Session["pin3"]) + "' and pin4='" + Convert.ToString(Session["pin4"]) + "' and pin5='" + Convert.ToString(Session["pin5"]) + "' and pin6='" + Convert.ToString(Session["pin6"]) + "'  and pin7='" + Convert.ToString(Session["pin7"]) + "' and pin8 ='" + Convert.ToString(Session["pin8"]) + "' and khata_no='" + dr_delete["khata_no"] + "' ");
                        }
                        dbTransaction.Commit();
                        gdvNewBhogvatdar.DataSource = ds_addkhata_delete;
                        gdvNewBhogvatdar.DataBind();
                    }
                    catch (Exception ex)
                    {
                        ExceptionHandling excpt = new ExceptionHandling();
                        if (Session["UserName"] != null)
                            Session["Error"] = Session["Error"] = excpt.Getex(ex, page_name, Convert.ToString(Session["UserName"]), Convert.ToString(Session["DataBaseName"]));
                        else
                            Session["Error"] = excpt.Getex(ex, page_name, "UNKNOWN", Convert.ToString(Session["DataBaseName"]));
                        lblMessage.Visible = true;
                        lblMessage.Text = ex.Message; //"Select Survey Numbers related to Owner selected : "+ ex.Message;
                        return;
                    }
                }
            }
            connection.Close();
        }

