                TextBox potkharaba = (TextBox)gdvOldBhogvatdar1.Rows[p].FindControl("grd2text13");

                double area = 0.000;
                double potkarea = 0.000;


                string area_akarni = null;
                DataSet dsform8a = new DataSet();
