                if (f7a_edit_cnt > 0)
                {
                    dsform8a = con.funReturnDataSet(Convert.ToString(Session["DataBaseName"]), Convert.ToString(Session["SchemaName"]) + ".edit_form7_area a," + Convert.ToString(Session["SchemaName"]) + ".edit_form7_khata b", "a.ccode,b.total_area_h,b.potkharaba,a.net_culti_area_h,a.na_area_h,a.potkharaba_a_h,a.potkharaba_b_h,b.anne,b.pai,b.khata_no,a.pin,a.pin1,a.pin2,a.pin3,a.pin4,a.pin5,a.pin6,a.pin7,a.pin8", "a.pin=b.pin and a.pin1=b.pin1 and a.pin2=b.pin2 and a.pin3=b.pin3 and a.pin4=b.pin4 and a.pin5=b.pin5 and a.pin6=b.pin6 and a.pin7=b.pin7 and a.pin8=b.pin8 and a.ccode=b.ccode and b.marked<>'Y' and (b.anne<>'0.00' or b.pai<>'0.00') and b.khata_type<>'1' and a.ccode='" + Convert.ToString(Session["ccode"]) + "'", "a.pin,a.pin1,a.pin2,a.pin3,a.pin4,a.pin5,a.pin6,a.pin7,a.pin8");
                    //  area = con.funReturnSingleValue(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".edit_form7_area", "net_culti_area_h||'#'||assessment", "ccode = '" + Convert.ToString(Session["ccode"]) + "' and pin='" + Convert.ToString(Session["pin"]) + "' and pin1='" + Convert.ToString(Session["pin1"]) + "' and pin2='" + Convert.ToString(Session["pin2"]) + "' and pin3='" + Convert.ToString(Session["pin3"]) + "' and pin4='" + Convert.ToString(Session["pin4"]) + "' and pin5='" + Convert.ToString(Session["pin5"]) + "' and pin6='" + Convert.ToString(Session["pin6"]) + "'  and pin7='" + Convert.ToString(Session["pin7"]) + "' and pin8 ='" + Convert.ToString(Session["pin8"]) + "'", "");
                }
                else
                {
                    dsform8a = con.funReturnDataSet(Convert.ToString(Session["DataBaseName"]), Convert.ToString(Session["SchemaName"]) + ".form7_area a," + Convert.ToString(Session["SchemaName"]) + ".form7_khata b", "a.ccode,b.total_area_h,b.potkharaba,a.net_culti_area_h,a.na_area_h,a.potkharaba_a_h,a.potkharaba_b_h,b.anne,b.pai,b.khata_no,a.pin,a.pin1,a.pin2,a.pin3,a.pin4,a.pin5,a.pin6,a.pin7,a.pin8", "a.pin=b.pin and a.pin1=b.pin1 and a.pin2=b.pin2 and a.pin3=b.pin3 and a.pin4=b.pin4 and a.pin5=b.pin5 and a.pin6=b.pin6 and a.pin7=b.pin7 and a.pin8=b.pin8 and a.ccode=b.ccode and b.marked<>'Y' and (b.anne<>'0.00' or b.pai<>'0.00') and b.khata_type<>'1' and a.ccode='" + Convert.ToString(Session["ccode"]) + "'", "a.pin,a.pin1,a.pin2,a.pin3,a.pin4,a.pin5,a.pin6,a.pin7,a.pin8");
                    // area_akarni = con.funReturnSingleValue(Session["DataBaseName"].ToString(), Session["SchemaName"].ToString() + ".form7_area", "net_culti_area_h||'#'||assessment", "ccode = '" + Convert.ToString(Session["ccode"]) + "' and pin='" + Convert.ToString(Session["pin"]) + "' and pin1='" + Convert.ToString(Session["pin1"]) + "' and pin2='" + Convert.ToString(Session["pin2"]) + "' and pin3='" + Convert.ToString(Session["pin3"]) + "' and pin4='" + Convert.ToString(Session["pin4"]) + "' and pin5='" + Convert.ToString(Session["pin5"]) + "' and pin6='" + Convert.ToString(Session["pin6"]) + "'  and pin7='" + Convert.ToString(Session["pin7"]) + "' and pin8 ='" + Convert.ToString(Session["pin8"]) + "'", "");
                }
                if (dsform8a.Tables[0].Rows.Count > 0)
                {
                    foreach (DataRow dr in dsform8a.Tables[0].Select("total_area_h = 0.000  and ( anne > 0 or pai > 0 ) "))
                    {
                        if (Convert.ToDouble(dr["anne"]) != 0.00 && Convert.ToDouble(dr["pai"]) != 0.00)
                        {
                            if ((Convert.ToDouble(dr["net_culti_area_h"]) + Convert.ToDouble(dr["na_area_h"])) > 0.0000)
                            {
                                area = Math.Round(((((Convert.ToDouble(dr["anne"])) + (Convert.ToDouble(dr["pai"]) / 12)) * ((Convert.ToDouble(dr["net_culti_area_h"])) + (Convert.ToDouble(dr["na_area_h"])))) / 16), 4);
                                dr["total_area_h"] = area;
                            }
                            else if ((Convert.ToDouble(dr["potkharaba_a_h"]) + Convert.ToDouble(dr["potkharaba_b_h"])) > 0.0000)
                            {
                                potkarea = Math.Round(((((Convert.ToDouble(dr["anne"])) + (Convert.ToDouble(dr["pai"]) / 12)) * ((Convert.ToDouble(dr["potkharaba_a_h"])) + (Convert.ToDouble(dr["potkharaba_b_h"])))) / 16), 4);
                                dr["potkharaba"] = potkarea;
                            }
                        }
                        else if (Convert.ToDouble(dr["anne"]) != 0.00 && Convert.ToDouble(dr["pai"]) == 0.00)
                        {
                            if ((Convert.ToDouble(dr["net_culti_area_h"]) + Convert.ToDouble(dr["na_area_h"])) > 0.0000)
                            {
                                area = Math.Round((((Convert.ToDouble(dr["net_culti_area_h"]) + Convert.ToDouble(dr["na_area_h"])) * Convert.ToDouble(dr["anne"])) / 16), 4);
                                dr["total_area_h"] = area;
                            }
                            else if ((Convert.ToDouble(dr["potkharaba_a_h"]) + Convert.ToDouble(dr["potkharaba_b_h"])) > 0.0000)
                            {
                                potkarea = Math.Round((((Convert.ToDouble(dr["potkharaba_a_h"]) + Convert.ToDouble(dr["potkharaba_b_h"])) * Convert.ToDouble(dr["anne"])) / 16), 4);
                                dr["potkharaba"] = potkarea;
                            }
                        }
                        else if (Convert.ToDouble(dr["anne"]) == 0.00 && Convert.ToDouble(dr["pai"]) != 0.00)
                        {
                            if ((Convert.ToDouble(dr["net_culti_area_h"]) + Convert.ToDouble(dr["na_area_h"])) > 0.0000)
                            {
                                area = Math.Round((((Convert.ToDouble(dr["net_culti_area_h"]) + Convert.ToDouble(dr["na_area_h"])) * (Convert.ToDouble(dr["pai"]) / 12)) / 16), 4);
                                dr["total_area_h"] = area;
                            }
                            else if ((Convert.ToDouble(dr["potkharaba_a_h"]) + Convert.ToDouble(dr["potkharaba_b_h"])) > 0.0000)
                            {
                                potkarea = Math.Round((((Convert.ToDouble(dr["potkharaba_a_h"]) + Convert.ToDouble(dr["potkharaba_b_h"])) * (Convert.ToDouble(dr["pai"]) / 12)) / 16), 4);
                                dr["potkharaba"] = potkarea;
                            }
                        }
                    }
                }



                if (area_akarni != "" && area_akarni != null && Convert.ToDecimal(area_akarni.Split('#')[1]) != 0 && Convert.ToDecimal(area_akarni.Split('#')[0]) != 0)
                    txtakarni.Text = Convert.ToString(Math.Round((Convert.ToDecimal(txtarea.Text) * (Convert.ToDecimal(area_akarni.Split('#')[1]) / Convert.ToDecimal(area_akarni.Split('#')[0]))), 2));
            }


        }
        catch (Exception ex)
        {
            ExceptionHandling excpt = new ExceptionHandling();
            if (Session["LoginID"] != null)
                Session["Error"] = excpt.Getex(ex, page_name, Convert.ToString(Session["LoginID"]), Convert.ToString(Session["DataBaseName"]));
            else
                Session["Error"] = excpt.Getex(ex, page_name, "UNKNOWN", Convert.ToString(Session["DataBaseName"]));
            string popupScript = "<script language='javascript'>alert('" + Convert.ToString(Session["Error"]) + "');</script>";
            ClientScript.RegisterStartupScript(GetType(), "PopupScript", popupScript);
        }
    }
